<?php
 declare(strict_types=1);
require __DIR__ . '/app.php';
require __DIR__ . '/training-storage.php';
require __DIR__ . '/training-permissions.php';
$config=lqr_config();$state=lqr_load_state();$userId=lqr_current_user_id($config);$user=lqr_get_user($state,$config,$userId);$error='';try{tcl_require_training_admin($user);}catch(Throwable $e){$error=$e->getMessage();}
