?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Action Receipts</title><link rel="stylesheet" href="assets/training-lab.css"></head><body class="tcl-app"><div class="tcl-shell"><aside class="tcl-sidebar"><a class="tcl-brand" href="training-lab.php"><span class="tcl-logo">MG</span><span><strong>Microgifter</strong><span>Action Receipts</span></span></a><nav class="tcl-nav"><a href="training-lab.php"><span class="tcl-nav-icon">⌂</span><span>Dashboard</span></a><a href="admin-training-review.php"><span class="tcl-nav-icon">✓</span><span>Review Queue</span></a><a class="active" href="admin-training-receipts.php"><span class="tcl-nav-icon">▣</span><span>Receipts</span></a><a href="training-rewards.php"><span class="tcl-nav-icon">◉</span><span>Rewards</span></a></nav></aside><main class="tcl-main"><header class="tcl-topbar"><button class="tcl-mobile-menu">☰</button><div class="tcl-search">⌕ <span>Receipts, reward issues, event timeline</span></div></header><section class="tcl-page-head"><div><span class="tcl-eyebrow">Verified Action Ledger</span><h1>Action Receipts</h1><p>Reviewer/admin access is required. Durable receipt records are created after approved proof.</p></div><a class="tcl-btn primary" href="admin-training-review.php">Review Proof</a></section><?php if($error):?><div class="tcl-card" style="margin-bottom:16px"><span class="tcl-pill is-danger"><?=lqr_h($error)?></span></div><?php endif;?><section class="tcl-grid cols-4"><div class="tcl-card tcl-kpi"><span>Receipts</span><strong><?=count($receipts)?></strong><small>Verified actions</small></div><div class="tcl-card tcl-kpi"><span>Reward Issues</span><strong><?=count($issues)?></strong><small>Eligibility records</small></div><div class="tcl-card tcl-kpi"><span>Events</span><strong><?=count($events)?></strong><small>Training log</small></div><div class="tcl-card tcl-kpi"><span>Storage</span><strong style="font-size:22px"><?=tcl_runtime_sql()?'SQL':'JSON'?></strong><small>Runtime mode</small></div></section><section class="tcl-layout" style="margin-top:22px"><div class="tcl-card"><div class="tcl-card-head"><div><h2>Receipt list</h2><p>Newest verified receipts.</p></div></div><div class="tcl-step-list"><?php if(!$receipts):?><div class="tcl-empty">No Action Receipts available.</div><?php endif;?><?php foreach($receipts as $r):?><div class="tcl-step verified"><span class="tcl-step-index">▣</span><div><h4><?=lqr_h(tcl_status_label((string)($r['receipt_type']??'receipt')))?></h4><p><?=lqr_h((string)($r['campaign_slug']??''))?> · <?=lqr_h((string)($r['task_slug']??$r['sequence_slug']??''))?> · <?=lqr_h((string)($r['created_at']??''))?></p><div class="tcl-tags"><span class="tcl-pill is-success"><?=lqr_h((string)($r['status']??'verified'))?></span><span class="tcl-pill is-purple"><?=number_format((int)($r['points_awarded']??0))?> pts</span></div></div></div><?php endforeach;?></div></div><aside class="tcl-card soft"><h2>Event timeline</h2><div class="tcl-step-list"><?php foreach(array_slice($events,0,8) as $e):?><div class="tcl-step"><span class="tcl-step-index">•</span><div><h4><?=lqr_h((string)$e['type'])?></h4><p><?=lqr_h((string)$e['message'])?> · <?=lqr_h((string)$e['at'])?></p></div></div><?php endforeach;?></div></aside></section></main></div><script src="assets/training-lab.js"></script></body></html>
